import CountDown from "~/components/public/countDown";
import { copyClipboard } from '@/utils/tools'
import QRCode from 'qrcodejs2'

export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
       link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  layout: "user_lauout",
  components: {
    CountDown,
  },
  async asyncData({ $get, query }) {
    const { data, code } = await $get("order/detail", {
      params: {
        id: query.id,
      },
    });

    if (code == 1) {
      return {
        orderDetail: data,
        id: query.id,
      };
    }

  },
  data() {
    return {
      orderDetail: {},
      showDeliverPop: false
    };
  },

  mounted() {
    if (this.orderDetail.delivery_type === 2) {
      this.creatQrCode(this.orderDetail.pickup_code)
    }
  },

  methods: {
    creatQrCode(content) {
        const qrcode = new QRCode(this.$refs.qrCodeUrl, {
            text: content,
            width: 106,
            height: 106,
            colorDark: '#333333',
            colorLight: '#ffffff',
            correctLevel: QRCode.CorrectLevel.H
        })
    },
    onCopyQRCode() {
      const content = this.orderDetail.pickup_code
      copyClipboard(content)
        .then(() => {
          this.$message.success('复制成功')
        })
        .catch(err => {
          this.$message.error('复制失败')
          console.log(err)
        })
    },

    async getOrderDetail() {
      const { data, code } = await this.$get("order/detail", {
        params: {
          id: this.id,
        },
      });
      if (code == 1) {
        this.orderDetail = data;
      }
    },
    handleOrder(type) {
      this.type = type;
      this.$confirm(this.getTipsText(type), {
        title: "温馨提示",
        center: true,
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        callback: (action) => {
          if (action == "confirm") {
            this.postOrder();
          }
        },
      });
    },
    async postOrder() {
      const { type, id } = this;
      let url = "";
      switch (type) {
        case 0:
          url = "order/cancel";
          break;
        case 1:
          url = "order/del";
          break;
        case 2:
          url = "order/confirm";
          break;
      }
      let { code, data, msg } = await this.$post(url, { id });
      if (code == 1) {
        this.$message({
          message: msg,
          type: "success",
        });
        if (type == 1) {
          setTimeout(() => {
            this.$router.go(-1);
          }, 1500);
        } else {
          this.getOrderDetail();
        }
      }
    },
    getTipsText(type) {
      switch (type) {
        case 0:
          return "确认取消订单吗？";
        case 1:
          return "确认删除订单吗?";
        case 2:
          return "确认收货吗?";
      }
    },
  },
  computed: {
    getOrderStatus() {
      return (status) => {
        let text = "";
        switch (status) {
          case 0:
            text = "待支付";
            break;
          case 1:
            text = "待发货";
            break;
          case 2:
            text = "待收货";
            break;
          case 3:
            text = "已完成";
            break;
          case 4:
            text = "订单已关闭";
            break;
        }
        return text;
      };
    },
    getCancelTime() {
      return (time) => time - Date.now() / 1000;
    },
  },
};
